/// Event monitor for real-time event processing
pub struct EventMonitor {
    /// Event receiver
    receiver: broadcast::Receiver<Event>,
    /// Event handlers
    handlers: Vec<Box<dyn EventHandler + Send + Sync>>,
    /// Whether the monitor is running
    running: bool,
}

/// Event handler trait
pub trait EventHandler {
    /// Handle an event
    fn handle_event(&mut self, event: &Event) -> Result<()>;
    /// Get handler name
    fn name(&self) -> &str;
    /// Check if handler should process this event
    fn should_handle(&self, event: &Event) -> bool {
        true
    }
}

impl EventMonitor {
    /// Create a new event monitor
    pub fn new() -> Result<Self> {
        let receiver = if let Some(stream) = get_event_stream() {
            stream
                .subscribe()
                .ok_or_else(|| anyhow::anyhow!("Event stream not configured for broadcasting"))?
        } else {
            anyhow::bail!("Event stream not initialized");
        };

        Ok(Self {
            receiver,
            handlers: Vec::new(),
            running: false,
        })
    }

    /// Add an event handler
    pub fn add_handler(&mut self, handler: Box<dyn EventHandler + Send + Sync>) {
        self.handlers.push(handler);
    }

    /// Start monitoring events
    pub async fn start(&mut self) -> Result<()> {
        self.running = true;
        println!("🎯 Event monitor started");

        while self.running {
            match self.receiver.recv().await {
                Ok(event) => {
                    for handler in &mut self.handlers {
                        if handler.should_handle(&event) {
                            if let Err(e) = handler.handle_event(&event) {
                                eprintln!("Handler {} failed: {}", handler.name(), e);
                            }
                        }
                    }
                }
                Err(broadcast::error::RecvError::Closed) => {
                    println!("📡 Event stream closed");
                    break;
                }
                Err(broadcast::error::RecvError::Lagged(n)) => {
                    eprintln!("⚠️ Event monitor lagged by {n} events");
                }
            }
        }

        Ok(())
    }

    /// Stop monitoring events
    pub fn stop(&mut self) {
        self.running = false;
    }
}

/// Default event handlers
/// Console event handler
pub struct ConsoleEventHandler {
    /// Whether to show metadata
    show_metadata: bool,
}

impl ConsoleEventHandler {
    pub fn new(show_metadata: bool) -> Self {
        Self { show_metadata }
    }
}

impl EventHandler for ConsoleEventHandler {
    fn handle_event(&mut self, event: &Event) -> Result<()> {
        let severity_icon = match event.severity {
            EventSeverity::Trace => "🔍",
            EventSeverity::Debug => "🐛",
            EventSeverity::Info => "ℹ️",
            EventSeverity::Warn => "⚠️",
            EventSeverity::Error => "❌",
            EventSeverity::Critical => "🚨",
        };

        println!(
            "{} [{}] {}: {}",
            severity_icon, event.event_type, event.source, event.message
        );

        if self.show_metadata && !event.metadata.is_empty() {
            for (key, value) in &event.metadata {
                println!("  {key}: {value}");
            }
        }

        Ok(())
    }

    fn name(&self) -> &str {
        "console"
    }

    fn should_handle(&self, event: &Event) -> bool {
        event.severity >= EventSeverity::Info
    }
}

/// Performance event handler
pub struct PerformanceEventHandler {
    /// Performance thresholds
    thresholds: HashMap<String, u64>,
}

impl PerformanceEventHandler {
    pub fn new() -> Self {
        let mut thresholds = HashMap::new();
        thresholds.insert("slow_operation".to_string(), 1000); // 1 second
        thresholds.insert("very_slow_operation".to_string(), 5000); // 5 seconds

        Self { thresholds }
    }
}

impl EventHandler for PerformanceEventHandler {
    fn handle_event(&mut self, event: &Event) -> Result<()> {
        if let Some(duration) = event.duration_ms {
            if duration > *self.thresholds.get("very_slow_operation").unwrap_or(&5000) {
                eprintln!(
                    "🚨 Very slow operation detected: {} took {}ms",
                    event.event_type, duration
                );
            } else if duration > *self.thresholds.get("slow_operation").unwrap_or(&1000) {
                eprintln!(
                    "⚠️ Slow operation detected: {} took {}ms",
                    event.event_type, duration
                );
            }
        }
        Ok(())
    }

    fn name(&self) -> &str {
        "performance"
    }

    fn should_handle(&self, event: &Event) -> bool {
        event.category == EventCategory::Performance || event.duration_ms.is_some()
    }
}

/// Error aggregation handler
pub struct ErrorAggregationHandler {
    /// Error counts by type
    error_counts: HashMap<String, u64>,
    /// Error threshold for alerts
    error_threshold: u64,
}

impl ErrorAggregationHandler {
    pub fn new(error_threshold: u64) -> Self {
        Self {
            error_counts: HashMap::new(),
            error_threshold,
        }
    }
}

impl EventHandler for ErrorAggregationHandler {
    fn handle_event(&mut self, event: &Event) -> Result<()> {
        if event.severity >= EventSeverity::Error {
            let count = self
                .error_counts
                .entry(event.event_type.clone())
                .or_insert(0);
            *count += 1;

            if *count >= self.error_threshold {
                eprintln!(
                    "🚨 Error threshold exceeded for {}: {} errors",
                    event.event_type, count
                );
            }
        }
        Ok(())
    }

    fn name(&self) -> &str {
        "error_aggregation"
    }

    fn should_handle(&self, event: &Event) -> bool {
        event.severity >= EventSeverity::Error
    }
}

