    #[test]
    fn test_event_creation() {
        let event = Event::new(
            EventSeverity::Info,
            EventCategory::HookStateMachine,
            "test_event".to_string(),
            "Test message".to_string(),
            "test_source".to_string(),
        );

        assert_eq!(event.severity, EventSeverity::Info);
        assert_eq!(event.category, EventCategory::HookStateMachine);
        assert_eq!(event.event_type, "test_event");
        assert_eq!(event.message, "Test message");
        assert_eq!(event.source, "test_source");
    }

    #[test]
    fn test_event_jsonl_serialization() {
        let event = Event::new(
            EventSeverity::Info,
            EventCategory::HookStateMachine,
            "test_event".to_string(),
            "Test message".to_string(),
            "test_source".to_string(),
        );

        let jsonl = event.to_jsonl().unwrap();
        assert!(jsonl.contains("test_event"));
        assert!(jsonl.contains("Test message"));
    }

    #[test]
    fn test_event_with_metadata() {
        let event = Event::new(
            EventSeverity::Info,
            EventCategory::HookStateMachine,
            "test_event".to_string(),
            "Test message".to_string(),
            "test_source".to_string(),
        )
        .with_metadata("key".to_string(), serde_json::json!("value"));

        assert_eq!(event.metadata.get("key"), Some(&serde_json::json!("value")));
    }
